     5→#version 330 core
     6→
     7→layout(location = 0) in vec3 a_Position;
     8→layout(location = 1) in vec3 a_Normal;
     9→layout(location = 2) in vec2 a_TexCoords;
    10→
    11→out vec3 v_FragPos;
    12→out vec3 v_Normal;
    13→out vec2 v_TexCoords;
    14→
    15→uniform mat4 u_Model;
    16→uniform mat4 u_View;
    17→uniform mat4 u_Projection;
    18→uniform mat3 u_NormalMatrix;
    19→
    20→void main()
    21→{
    22→    v_FragPos = vec3(u_Model * vec4(a_Position, 1.0));
    23→    v_Normal = u_NormalMatrix * a_Normal;
    24→    v_TexCoords = a_TexCoords;
    25→
    26→    gl_Position = u_Projection * u_View * vec4(v_FragPos, 1.0);
    27→}
    28→
    29→#type fragment
    30→#version 330 core
    31→
    32→// 多渲染目标输出
    33→layout(location = 0) out vec4 FragColor;
    34→layout(location = 1) out int EntityID;
    35→
    36→in vec3 v_FragPos;
    37→in vec3 v_Normal;
    38→in vec2 v_TexCoords;
    39→
    40→// 材质
    41→struct Material {
    42→    sampler2D diffuse;
    43→    sampler2D specular;
    44→    float shininess;
    45→};
    46→
    47→// 方向光
    48→struct DirLight {
    49→    vec3 direction;
    50→    vec3 ambient;
    51→    vec3 diffuse;
    52→    vec3 specular;
    53→};
    54→
    55→// 点光源
    56→struct PointLight {
    57→    vec3 position;
    58→    float constant;
    59→    float linear;
    60→    float quadratic;
    61→    vec3 ambient;
    62→    vec3 diffuse;
    63→    vec3 specular;
    64→};
    65→
    66→// 聚光灯
    67→struct SpotLight {
    68→    vec3 position;
    69→    vec3 direction;
    70→    float cutOff;
    71→    float outerCutOff;
    72→    float constant;
    73→    float linear;
    74→    float quadratic;
    75→    vec3 ambient;
    76→    vec3 diffuse;
    77→    vec3 specular;
    78→};
    79→
    80→#define NR_POINT_LIGHTS 4
    81→
    82→uniform vec3 u_ViewPos;
    83→uniform Material material;
    84→uniform DirLight dirLight;
    85→uniform PointLight pointLight[NR_POINT_LIGHTS];
    86→uniform SpotLight spotLight;
    87→uniform int u_EntityID;
    88→
    89→// 函数声明
    90→vec3 CalcDirLight(DirLight light, vec3 normal, vec3 viewDir);
    91→vec3 CalcPointLight(PointLight light, vec3 normal, vec3 fragPos, vec3 viewDir);
    92→vec3 CalcSpotLight(SpotLight light, vec3 normal, vec3 fragPos, vec3 viewDir);
    93→
    94→void main()
    95→{
    96→    vec3 norm = normalize(v_Normal);
    97→    vec3 viewDir = normalize(u_ViewPos - v_FragPos);
    98→
    99→    // 方向光
   100→    vec3 result = CalcDirLight(dirLight, norm, viewDir);
   101→
   102→    // 点光源
   103→    for (int i = 0; i < NR_POINT_LIGHTS; i++) {
   104→        result += CalcPointLight(pointLight[i], norm, v_FragPos, viewDir);
   105→    }
   106→
   107→    // 聚光灯
   108→    result += CalcSpotLight(spotLight, norm, v_FragPos, viewDir);
   109→
   110→    FragColor = vec4(result, 1.0);
   111→    EntityID = u_EntityID;
   112→}
   113→
   114→vec3 CalcDirLight(DirLight light, vec3 normal, vec3 viewDir)
   115→{
   116→    vec3 lightDir = normalize(-light.direction);
   117→    float diff = max(dot(normal, lightDir), 0.0);
   118→    vec3 reflectDir = reflect(-lightDir, normal);
   119→    float spec = pow(max(dot(viewDir, reflectDir), 0.0), material.shininess);
   120→
   121→    vec3 ambient = light.ambient * vec3(texture(material.diffuse, v_TexCoords));
   122→    vec3 diffuse = light.diffuse * diff * vec3(texture(material.diffuse, v_TexCoords));
   123→    vec3 specular = light.specular * spec * vec3(texture(material.specular, v_TexCoords));
   124→
   125→    return ambient + diffuse + specular;
   126→}
   127→
   128→vec3 CalcPointLight(PointLight light, vec3 normal, vec3 fragPos, vec3 viewDir)
   129→{
   130→    vec3 lightDir = normalize(light.position - fragPos);
   131→    float diff = max(dot(normal, lightDir), 0.0);
   132→    vec3 reflectDir = reflect(-lightDir, normal);
   133→    float spec = pow(max(dot(viewDir, reflectDir), 0.0), material.shininess);
   134→
   135→    float distance = length(light.position - fragPos);
   136→    float attenuation = 1.0 / (light.constant + light.linear * distance + light.quadratic * distance * distance);
   137→
   138→    vec3 ambient = light.ambient * vec3(texture(material.diffuse, v_TexCoords));
   139→    vec3 diffuse = light.diffuse * diff * vec3(texture(material.diffuse, v_TexCoords));
   140→    vec3 specular = light.specular * spec * vec3(texture(material.specular, v_TexCoords));
   141→
   142→    return (ambient + diffuse + specular) * attenuation;
   143→}
   144→
   145→vec3 CalcSpotLight(SpotLight light, vec3 normal, vec3 fragPos, vec3 viewDir)
   146→{
   147→    vec3 lightDir = normalize(light.position - fragPos);
   148→    float diff = max(dot(normal, lightDir), 0.0);
   149→    vec3 reflectDir = reflect(-lightDir, normal);
   150→    float spec = pow(max(dot(viewDir, reflectDir), 0.0), material.shininess);
   151→
   152→    float distance = length(light.position - fragPos);
   153→    float attenuation = 1.0 / (light.constant + light.linear * distance + light.quadratic * distance * distance);
   154→
   155→    float theta = dot(lightDir, normalize(-light.direction));
   156→    float epsilon = light.cutOff - light.outerCutOff;
   157→    float intensity = clamp((theta - light.outerCutOff) / epsilon, 0.0, 1.0);
   158→
   159→    vec3 ambient = light.ambient * vec3(texture(material.diffuse, v_TexCoords));
   160→    vec3 diffuse = light.diffuse * diff * vec3(texture(material.diffuse, v_TexCoords));
   161→    vec3 specular = light.specular * spec * vec3(texture(material.specular, v_TexCoords));
   162→
   163→    ambient *= attenuation;
   164→    diffuse *= attenuation * intensity;
   165→    specular *= attenuation * intensity;
   166→
   167→    return ambient + diffuse + specular;
   168→}
